# backend/encryption.py
import base64
from cryptography.fernet import Fernet

def get_user_fernet(user_id: str) -> Fernet:
    """Derive a per-user Fernet key from the KMS-held master key.
    In production: fetch from AWS KMS / GCP KMS, not env var.
    """
    import hashlib, os
    master = os.environ["MESSAGE_ENCRYPTION_KEY"].encode()
    derived = hashlib.pbkdf2_hmac("sha256", user_id.encode(), master, 100_000, dklen=32)
    key = base64.urlsafe_b64encode(derived)
    return Fernet(key)

def encrypt_content(user_id: str, plaintext: str) -> str:
    return get_user_fernet(user_id).encrypt(plaintext.encode()).decode()

def decrypt_content(user_id: str, ciphertext: str) -> str:
    return get_user_fernet(user_id).decrypt(ciphertext.encode()).decode()
